const slug = $('When chat message received').item.json.body?.slug || $('When chat message received').item.json.slug || '';
const start_time = $fromAI('start_time', 'Start of the interval to check, in ISO 8601 format');
const end_time = $fromAI('end_time', 'End of the interval to check, in ISO 8601 format');

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://api:3000/api/widget/' + slug + '/calendar/available',
    body: { start_time, end_time },
    headers: { 'Content-Type': 'application/json' }
  });
  return JSON.stringify(response);
} catch (e) {
  const msg = e.response?.body?.detail || e.message || 'Calendar check failed';
  return JSON.stringify({ available: false, message: msg });
}
